cat <<'EOF' > manager/tools/generate_report.js
const { Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell, HeadingLevel, WidthType, BorderStyle, ShadingType } = require('docx');
const fs = require('fs');

async function generateReport() {
    const csvData = fs.readFileSync('promotion_candidates.csv', 'utf8');
    const lines = csvData.trim().split('\n');
    const headers = lines[0].split(',');
    const rows = lines.slice(1).map(line => line.split(','));

    const border = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
    const borders = { top: border, bottom: border, left: border, right: border };

    const tableRows = [
        new TableRow({
            children: headers.map(header => new TableCell({
                borders,
                width: { size: 9360 / headers.length, type: WidthType.DXA },
                shading: { fill: "D5E8F0", type: ShadingType.CLEAR },
                children: [new Paragraph({ children: [new TextRun({ text: header, bold: true })] })]
            }))
        }),
        ...rows.map(row => new TableRow({
            children: row.map(cell => new TableCell({
                borders,
                width: { size: 9360 / headers.length, type: WidthType.DXA },
                children: [new Paragraph({ children: [new TextRun(cell)] })]
            }))
        }))
    ];

    const doc = new Document({
        styles: {
            default: { document: { run: { font: "Arial", size: 24 } } },
            paragraphStyles: [
                {
                    id: "Heading1",
                    name: "Heading 1",
                    basedOn: "Normal",
                    next: "Normal",
                    quickFormat: true,
                    run: { size: 32, bold: true, font: "Arial" },
                    paragraph: { spacing: { before: 240, after: 240 }, outlineLevel: 0 },
                }
            ]
        },
        sections: [{
            children: [
                new Paragraph({ heading: HeadingLevel.HEADING_1, children: [new TextRun("Promotion Candidates Report")] }),
                new Paragraph({
                    children: [new TextRun("This report identifies employees eligible for promotion based on their performance and tenure. " + 
                        "The following individuals have demonstrated exceptional performance with a score of 4 or higher and have been " + 
                        "part of the organization for over five years, showing sustained commitment and excellence.")]
                }),
                new Paragraph({ children: [new TextRun("")] }), // Spacer
                new Table({
                    width: { size: 9360, type: WidthType.DXA },
                    columnWidths: Array(headers.length).fill(9360 / headers.length),
                    rows: tableRows
                })
            ]
        }]
    });

    const buffer = await Packer.toBuffer(doc);
    fs.writeFileSync('outputs/promotion_report.docx', buffer);
    console.log("WordReportCreated: TRUE");
}

generateReport().catch(console.error);
EOF

bun run manager/tools/generate_report.js
